 import { useState } from "react";
import { useParams } from "react-router-dom";

function PostDetails() {
  const { id } = useParams();

  const posts = [
    {
      id: 1,
      title: "MERN Stack Guide",
      image:
        "https://images.unsplash.com/photo-1516321318423-f06f85e504b3",
      content:
        "MERN Stack is a powerful technology stack consisting of MongoDB, Express.js, React.js and Node.js. It is widely used for building full-stack web applications."
    },
    {
      id: 2,
      title: "React Hooks Tutorial",
      image:
        "https://images.unsplash.com/photo-1633356122544-f134324a6cee",
      content:
        "React Hooks like useState and useEffect help developers manage state and side effects easily."
    },
    {
      id: 3,
      title: "Node.js Backend",
      image:
        "https://images.unsplash.com/photo-1558494949-ef010cbdcc31",
      content:
        "Node.js allows developers to build fast and scalable backend APIs using JavaScript."
    }
  ];

  const post = posts.find((p) => p.id === Number(id));

  const [comment, setComment] = useState("");
  const [comments, setComments] = useState([
    "Great article 👍",
    "Very helpful for beginners."
  ]);

  const handleComment = () => {
    if (comment.trim() === "") return;

    setComments([...comments, comment]);
    setComment("");
  };

  if (!post) {
    return <h2>Post Not Found</h2>;
  }

  return (
    <div
      style={{
        width: "80%",
        margin: "40px auto"
      }}
    >
      <img
        src={post.image}
        alt={post.title}
        style={{
          width: "100%",
          borderRadius: "20px"
        }}
      />

      <h1
        style={{
          marginTop: "20px"
        }}
      >
        {post.title}
      </h1>

      <p
        style={{
          marginTop: "20px",
          lineHeight: "1.8"
        }}
      >
        {post.content}
      </p>

      <h2
        style={{
          marginTop: "40px"
        }}
      >
        Comments
      </h2>

      {comments.map((item, index) => (
        <div
          key={index}
          className="comment-box"
          style={{
            background: "#f5f5f5",
            padding: "10px",
            borderRadius: "10px",
            marginBottom: "10px"
          }}
        >
          {item}
        </div>
      ))}

      <textarea
        rows="4"
        placeholder="Add Comment"
        value={comment}
        onChange={(e) => setComment(e.target.value)}
        style={{
          width: "100%",
          padding: "10px",
          marginTop: "15px"
        }}
      />

      <button
        onClick={handleComment}
        style={{
          marginTop: "15px",
          padding: "10px 20px",
          border: "none",
          borderRadius: "8px",
          cursor: "pointer"
        }}
      >
        Submit Comment
      </button>
    </div>
  );
}

export default PostDetails;
